let expression="";
const expressionEl=document.querySelector("#expression");
const resultEl=document.querySelector("#result");
const operators=["+","-","*","/"];
function render(message=""){expressionEl.textContent=expression||"0";resultEl.textContent=message||expression||"0"}
function append(value){const last=expression.at(-1);if(operators.includes(value)&&operators.includes(last)){expression=expression.slice(0,-1)+value}else if(value==="."&&expression.split(/[+\-*/]/).at(-1).includes(".")){return}else{expression+=value}render()}
function calculate(){const match=expression.match(/^(-?\d+(?:\.\d+)?)\s*([+\-*/])\s*(-?\d+(?:\.\d+)?)$/);if(!match){render("Complete one calculation");return}const a=Number(match[1]),op=match[2],b=Number(match[3]);if(op==="/"&&b===0){render("Cannot divide by zero");return}const result=op==="+"?a+b:op==="-"?a-b:op==="*"?a*b:a/b;expression=String(Number(result.toFixed(10)));render()}
document.querySelector("#keypad").addEventListener("click",event=>{const button=event.target.closest("button");if(!button)return;if(button.dataset.value)append(button.dataset.value);if(button.dataset.action==="clear"){expression="";render()}if(button.dataset.action==="backspace"){expression=expression.slice(0,-1);render()}if(button.dataset.action==="calculate")calculate()});
window.addEventListener("keydown",event=>{if(/[0-9.+\-*/]/.test(event.key))append(event.key);if(event.key==="Enter")calculate();if(event.key==="Backspace"){expression=expression.slice(0,-1);render()}if(event.key==="Escape"){expression="";render()}});render();

