from pathlib import Path
from datetime import date
import json

DATA_FILE=Path("expenses.json")

def load_expenses():
    if not DATA_FILE.exists() or not DATA_FILE.read_text().strip():
        return []
    try:
        data=json.loads(DATA_FILE.read_text())
        return data if isinstance(data,list) else []
    except json.JSONDecodeError:
        return []

def save_expenses(expenses):
    DATA_FILE.write_text(json.dumps(expenses,indent=2))

def add_expense(expenses,date_value,category,description,amount):
    amount=float(amount)
    if amount<=0:
        raise ValueError("Amount must be greater than zero")
    expense={"date":date_value,"category":category.strip() or "Other","description":description.strip(),"amount":amount}
    expenses.append(expense)
    return expense

def category_totals(expenses):
    totals={}
    for expense in expenses:
        category=expense["category"]
        totals[category]=totals.get(category,0)+expense["amount"]
    return totals

def print_summary(expenses):
    print(f"Total: £{sum(x['amount'] for x in expenses):.2f}")
    for category,total in category_totals(expenses).items():
        print(f"{category}: £{total:.2f}")

def main():
    expenses=load_expenses()
    while True:
        choice=input("\n[A]dd [L]ist [S]ummary [Q]uit: ").strip().lower()
        if choice=="q": break
        if choice=="a":
            try:
                add_expense(expenses,input("Date [YYYY-MM-DD]: ") or date.today().isoformat(),input("Category: "),input("Description: "),input("Amount: "))
                save_expenses(expenses)
            except ValueError as error: print(error)
        elif choice=="l":
            for item in expenses: print(item)
        elif choice=="s": print_summary(expenses)

if __name__=="__main__": main()

