import java.util.ArrayList;
import java.util.List;

public class TaskService {
    private final List<Task> tasks = new ArrayList<>();
    private int nextId = 1;
    public Task create(String title){ Task task = new Task(nextId++, title); tasks.add(task); return task; }
    public List<Task> listTasks(){ return new ArrayList<>(tasks); }
    public Task complete(int id){ Task task = tasks.stream().filter(t -> t.getId()==id).findFirst().orElseThrow(() -> new IllegalArgumentException("Task not found")); task.complete(); return task; }
}

